def test_decision_table_channel_cap_combinations(auth_headers, account_id, base_url, regulatory_cap):
    import requests
    channels = ["online", "atm", "branch"]
    failures = []
    for channel in channels:
        over_cap = regulatory_cap(channel) + 1
        payload = {"channel": channel, "daily_limit": over_cap}
        resp = requests.patch(
            f"{base_url}/accounts/{account_id}/limits",
            json=payload,
            headers=auth_headers,
        )
        if resp.status_code != 422:
            failures.append(
                f"channel={channel} limit={over_cap}: expected 422 got {resp.status_code}"
            )
    assert not failures, "Cap enforcement failed for: " + "; ".join(failures)
